import React, { useEffect, useRef, useState } from "react";
import flatpickr from "flatpickr";
import "flatpickr/dist/flatpickr.min.css";
import "../styles/booking.css";
import { useNavigate } from "react-router-dom";

const API_BASE = process.env.REACT_APP_API_URL || "http://127.0.0.1:8000";

export default function Reservation() {
  const navigate = useNavigate();
  const token = localStorage.getItem("access_token");

  // 🔐 AUTH GUARD
  useEffect(() => {
    if (!token) {
      navigate("/login", { replace: true });
    }
  }, [token, navigate]);

  if (!token) return null;

  const [rooms, setRooms] = useState([]);
  const [reservedRanges, setReservedRanges] = useState([]);
  const [errorMsg, setErrorMsg] = useState("");

  const dateInputRef = useRef(null);
  const fpRef = useRef(null);

  const [selectedRoom, setSelectedRoom] = useState(null);
  const [roomDropdownOpen, setRoomDropdownOpen] = useState(false);
  const [adults, setAdults] = useState(1);
  const [numRooms, setNumRooms] = useState(1);

  const [form, setForm] = useState({
    reservation_dates: "",
    room_type: "",
    name: "",
    email: "",
    phone: "",
    message: "",
  });

  // ================================
  // LOAD ROOMS + RESERVATIONS
  // ================================
  useEffect(() => {
    let mounted = true;

    async function loadData() {
      try {
        const rRes = await fetch(`${API_BASE}/api/rooms/`);
        const roomsJson = await rRes.json();

        const roomsNormalized = roomsJson.map((r) => ({
          room_id: r.id,
          room_name: r.room_name,
          price: r.price,
          image: r.images?.[0]?.image
            ? `${API_BASE}${r.images[0].image}`
            : "/assets/images/uploads/default.jpg",
        }));

        const rvRes = await fetch(`${API_BASE}/api/reservations/`, {
          headers: {
            Authorization: `Bearer ${token}`,
          },
        });
        const rvJson = await rvRes.json();

        const ranges = rvJson.map((it) => {
          const to = new Date(it.check_out);
          to.setDate(to.getDate() - 1);
          return { from: it.check_in, to: to.toISOString().slice(0, 10) };
        });

        if (!mounted) return;

        setRooms(roomsNormalized);
        setReservedRanges(ranges);

        if (roomsNormalized.length > 0) {
          setSelectedRoom(roomsNormalized[0]);
          setForm((f) => ({ ...f, room_type: roomsNormalized[0].room_name }));
        }
      } catch (err) {
        console.error(err);
        setErrorMsg("Failed to load data");
      }
    }

    loadData();
    return () => (mounted = false);
  }, [token]);

  // ================================
  // DATE PICKER
  // ================================
  useEffect(() => {
    if (!dateInputRef.current) return;

    if (fpRef.current) fpRef.current.destroy();

    fpRef.current = flatpickr(dateInputRef.current, {
      mode: "range",
      minDate: "today",
      dateFormat: "Y-m-d",
      disable: reservedRanges,
      onClose: (_, dateStr) =>
        setForm((f) => ({ ...f, reservation_dates: dateStr })),
    });

    return () => fpRef.current?.destroy();
  }, [reservedRanges]);

  // ================================
  // FORM HANDLERS
  // ================================
  const handleInput = (e) =>
    setForm((f) => ({ ...f, [e.target.name]: e.target.value }));

  const handleSubmit = async (e) => {
    e.preventDefault();
    setErrorMsg("");

    const [check_in, check_out] = form.reservation_dates.split(" to ");
    if (!check_in || !check_out) {
      setErrorMsg("Please select dates");
      return;
    }

    try {
      const resp = await fetch(`${API_BASE}/api/reservations/`, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          Authorization: `Bearer ${token}`, // 🔑 REQUIRED
        },
        body: JSON.stringify({
          name: form.name,
          email: form.email,
          phone: form.phone,
          adults,
          children: 0,
          check_in,
          check_out,
          room_type: form.room_type,
          rooms: numRooms,
          message: form.message,
        }),
      });

      if (!resp.ok) throw new Error("Booking failed");

      alert("✅ Reservation successful!");
      navigate("/");
    } catch (err) {
      setErrorMsg(err.message);
    }
  };

  // ================================
  // UI
  // ================================
  return (
    <section className="reservation-section">
      <div className="reservation-container">
        {errorMsg && <p className="error">❌ {errorMsg}</p>}

        <form onSubmit={handleSubmit}>
          <label>Select Dates</label>
          <input ref={dateInputRef} readOnly placeholder="Check-in — Check-out" />

          <label>Room</label>
          <select
            value={form.room_type}
            onChange={(e) =>
              setForm((f) => ({ ...f, room_type: e.target.value }))
            }
          >
            {rooms.map((r) => (
              <option key={r.room_id}>{r.room_name}</option>
            ))}
          </select>

          <input name="name" placeholder="Full Name" required onChange={handleInput} />
          <input name="email" type="email" placeholder="Email" required onChange={handleInput} />
          <input name="phone" placeholder="Phone" required onChange={handleInput} />
          <textarea name="message" placeholder="Special Requests" onChange={handleInput} />

          <button type="submit" className="check-btn">
            Book Now
          </button>
        </form>
      </div>
    </section>
  );
}
